args.new_str:
{
  description = "ZOS Emacs Search Plugin";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
  };

  outputs = { self, nixpkgs }:
    let
      system = "x86_64-linux";
      pkgs = nixpkgs.legacyPackages.${system};
    in {
      packages.${system}.default = pkgs.writeShellScriptBin "emacs-search" ''
        ${pkgs.python3.withPackages (ps: [ ps.flask ])}/bin/python3 ${./emacs_search.py}
      '';

      apps.${system}.default = {
        type = "app";
        program = "${self.packages.${system}.default}/bin/emacs-search";
      };
    };
}

args.old_str:
{
  description = "ZOS Emacs Search Plugin";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
  };

  outputs = { self, nixpkgs }:
    let
      system = "x86_64-linux";
      pkgs = nixpkgs.legacyPackages.${system};
    in {
      packages.${system}.default = pkgs.python3Packages.buildPythonApplication {
        pname = "emacs-search";
        version = "0.1.0";

        src = ./.;

        propagatedBuildInputs = with pkgs.python3Packages; [
          flask
        ];

        installPhase = ''
          mkdir -p $out/bin
          cp emacs_search.py $out/bin/emacs-search
          chmod +x $out/bin/emacs-search
        '';

        meta = {
          description = "ZOS Emacs Search Plugin - Search inside Emacs buffers";
          homepage = "https://github.com/meta-introspector/zos-server";
        };
      };

      apps.${system}.default = {
        type = "app";
        program = "${self.packages.${system}.default}/bin/emacs-search";
      };
    };
}

